SELECT attribute_name, attribute_value 
FROM site_attributes 
WHERE site_id = 12150;

SELECT sa.*, sr.*
FROM site_attributes sa
JOIN site_readings sr ON sa.site_id = sr.site_id;

SELECT site_id, recorded_at 
FROM site_attributes 
ORDER BY recorded_at DESC;

SELECT AVG(attribute_value) AS average_attribute_value
FROM site_attributes
WHERE site_id = 12150;

SELECT reading_date, value
FROM site_readings
ORDER BY reading_date ASC;

SELECT attribute_name, attribute_value 
FROM site_attributes 
WHERE attribute_name = 'humidity' AND site_id = 12150;
